import React, { useState, useEffect } from 'react';
import { ShoppingCart, MapPin, Store, Plus, Loader2, ImageIcon } from 'lucide-react';
import { useNavigate } from 'react-router-dom'; // Para navegar al carrito
import { api } from '../services/api';
import { useCart } from '../context/CartContext';

const CLOUD_NAME = "dwpgncjgn"; 

const PanelCliente = () => {
    const [ofertasPorLocal, setOfertasPorLocal] = useState({});
    const [loading, setLoading] = useState(true);
    const [userCoords, setUserCoords] = useState(null);
    const { addToCart, count, total } = useCart();
    const navigate = useNavigate();

    // 1. Obtener ubicación del usuario al cargar
    useEffect(() => {
        if ("geolocation" in navigator) {
            navigator.geolocation.getCurrentPosition(
                (pos) => {
                    console.log("Ubicación obtenida:", pos.coords.latitude, pos.coords.longitude);
                    setUserCoords({ lat: pos.coords.latitude, lng: pos.coords.longitude });
                },
                (err) => console.warn("El cliente denegó la ubicación."),
                { enableHighAccuracy: true }
            );
        }
    }, []);

    useEffect(() => {
        const cargarDatos = async () => {
            try {
                setLoading(true);
                const data = await api.getTodasLasOfertas();
                
                const agrupado = data.reduce((acc, oferta) => {
                    const localData = oferta.local || {};
                    const nombreLocal = localData.nombre || 'Sucursal';
                    if (!acc[nombreLocal]) acc[nombreLocal] = { info: localData, productos: [] };
                    acc[nombreLocal].productos.push(oferta);
                    return acc;
                }, {});

                setOfertasPorLocal(agrupado);
            } catch (err) {
                console.error("Error al cargar ofertas:", err);
            } finally {
                setLoading(false);
            }
        };
        cargarDatos();
    }, []);

    // 2. Cálculo de distancia (Haversine)
    const getDistancia = (localInfo) => {
        // Buscamos coordenadas en location o directamente en el objeto info
        const lat = localInfo?.location?.lat || localInfo?.lat;
        const lng = localInfo?.location?.lng || localInfo?.lng;

        if (!userCoords || !lat || !lng) return "---";
        
        const R = 6371; 
        const dLat = (lat - userCoords.lat) * Math.PI / 180;
        const dLon = (lng - userCoords.lng) * Math.PI / 180;
        const a = 
            Math.sin(dLat/2) * Math.sin(dLat/2) +
            Math.cos(userCoords.lat * Math.PI / 180) * Math.cos(lat * Math.PI / 180) * Math.sin(dLon/2) * Math.sin(dLon/2);
        const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
        const d = R * c;
        
        return d < 1 ? `${(d * 1000).toFixed(0)}m` : `${d.toFixed(1)}km`;
    };

    const construirUrlImagen = (publicId) => {
        if (!publicId || publicId === 'placeholder_id') return null;
        return `https://res.cloudinary.com/${CLOUD_NAME}/image/upload/w_400,h_300,c_fill,f_auto,q_auto/${publicId}`;
    };

    if (loading) return (
        <div style={centerState}>
            <Loader2 size={40} color="#e67e22" className="animate-spin" />
            <p style={{marginTop: 15, color: '#64748b'}}>Cargando el radar de ofertas...</p>
        </div>
    );

    return (
        <div style={container}>
            <header style={headerStyle}>
                <div>
                    <h1 style={titleStyle}>Ofertas Cerca</h1>
                    <p style={{margin: 0, color: '#94a3b8', fontSize: '0.9rem'}}>Tafí Viejo, Tucumán</p>
                </div>
                {/* Botón de Carrito ahora es clickeable */}
                <div style={cartFloatingCard} onClick={() => navigate('/carrito')}>
                    <ShoppingCart color="#e67e22" size={20} />
                    <span style={{fontWeight: 'bold'}}>${total.toLocaleString()}</span>
                    <div style={badgeCount}>{count}</div>
                </div>
            </header>

            {Object.keys(ofertasPorLocal).map(nombre => (
                <div key={nombre} style={localSection}>
                    <div style={localHeader}>
                        <div style={localIconCircle}>
                            <Store size={20} color="white" />
                        </div>
                        <div style={{flex: 1}}>
                            <div style={{display:'flex', justifyContent:'space-between', alignItems:'center'}}>
                                <h2 style={localTitle}>{nombre}</h2>
                                <span style={distanciaBadge}>
                                    <MapPin size={12} /> {getDistancia(ofertasPorLocal[nombre].info)}
                                </span>
                            </div>
                            <p style={localSub}>{ofertasPorLocal[nombre].info?.direccion || 'Dirección no disponible'}</p>
                        </div>
                    </div>

                    <div style={scrollContainer}>
                        {ofertasPorLocal[nombre].productos.map(prod => {
                            const urlImagen = construirUrlImagen(prod.publicId);
                            
                            return (
                                <div key={prod._id} style={productCard}>
                                    <div style={imageBox}>
                                        {urlImagen ? (
                                            <img 
                                                src={urlImagen} 
                                                alt={prod.producto} 
                                                style={imgStyle}
                                                onError={(e) => { e.target.style.display = 'none'; e.target.parentNode.style.background = '#f1f5f9'; }}
                                            />
                                        ) : (
                                            <div style={placeholderIcon}>
                                                <ImageIcon size={30} color="#cbd5e1" />
                                            </div>
                                        )}
                                        <div style={stockBadge(prod.stock)}>
                                            {prod.stock > 0 ? `${prod.stock} disp.` : 'Agotado'}
                                        </div>
                                    </div>

                                    <div style={infoBox}>
                                        <div style={categoryTag}>{prod.categoria}</div>
                                        <h4 style={prodTitle}>{prod.producto}</h4>
                                        <div style={priceContainer}>
                                            <span style={newPrice}>${prod.precioNuevo}</span>
                                            <span style={oldPrice}>${prod.precioViejo}</span>
                                        </div>
                                        <button 
                                            style={prod.stock > 0 ? btnAdd : btnDisabled}
                                            onClick={() => addToCart(prod)}
                                            disabled={prod.stock <= 0}
                                        >
                                            <Plus size={16} /> Agregar
                                        </button>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>
            ))}
        </div>
    );
};

